// SPDX-License-Identifier: MIT
pragma solidity ^0.8.35;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IGameManager {
    enum RoundState { OPEN, BETTING_CLOSED, RESOLVED, CANCELLED }

    struct Round {
        uint256 id;
        address house;
        uint8 gridSize;
        uint8 numColours;
        uint256 minBet;
        uint256 maxBet;
        bytes32 commitHash;
        bytes32 revealedSeed;
        uint8 winningColour;
        uint256 bettingWindowStart;
        uint256 bettingWindowEnd;
        RoundState state;
    }

    function getRound(uint256 roundId) external view returns (Round memory);
}

interface IConfig {
    function houseFeePercentage() external view returns (uint256);
}

contract Betting is ReentrancyGuard {

    // ── Structs ──────────────────────────────────────────────────────────────

    struct Bet {
        address player;
        uint8 chosenColour;
        uint256 amount;      // in wei
        uint256 timestamp;   // block.timestamp when bet was placed
        uint256 multiplier;  // scaled by 1000 (e.g. 2500 = 2.5×)
        bool claimed;
    }

    // ── State ────────────────────────────────────────────────────────────────

    IGameManager public immutable gameManager;
    IConfig public immutable config;

    /// @dev round ID → all bets placed in that round
    mapping(uint256 => Bet[]) public bets;

    /// @dev round ID → player address → indices into bets[roundId]
    mapping(uint256 => mapping(address => uint256[])) public playerBetIndices;

    /// @dev round ID → total ETH wagered (wei)
    mapping(uint256 => uint256) public totalPot;

    /// @dev round ID → whether the house has already withdrawn its fee
    mapping(uint256 => bool) public houseFeeWithdrawn;

    // ── Events ───────────────────────────────────────────────────────────────

    event BetPlaced(
        uint256 indexed roundId,
        address indexed player,
        uint8 chosenColour,
        uint256 amount,
        uint256 multiplier
    );

    event WinningsClaimed(
        uint256 indexed roundId,
        address indexed player,
        uint256 payout
    );

    event RefundClaimed(
        uint256 indexed roundId,
        address indexed player,
        uint256 refund
    );

    event HouseFeeWithdrawn(
        uint256 indexed roundId,
        address indexed house,
        uint256 fee
    );

    // ── Errors ───────────────────────────────────────────────────────────────

    error RoundNotOpen();
    error BettingWindowExpired();
    error BetBelowMinimum(uint256 sent, uint256 minimum);
    error BetAboveMaximum(uint256 sent, uint256 maximum);
    error InvalidColour(uint8 colour, uint8 numColours);
    error HouseCannotBet();
    error RoundNotResolved();
    error RoundNotCancelled();
    error NoBetsToProcess();
    error NotRoundHouse();
    error FeeAlreadyWithdrawn();
    error TransferFailed();

    // ── Constructor ──────────────────────────────────────────────────────────

    constructor(address _gameManager, address _config) {
        gameManager = IGameManager(_gameManager);
        config = IConfig(_config);
    }

    // ── External: Place Bet ──────────────────────────────────────────────────

    /// @notice Place a bet on a colour in an open round.
    /// @param roundId  The ID of the round to bet on.
    /// @param colour   Zero-based colour index (must be < round.numColours).
    function placeBet(uint256 roundId, uint8 colour) external payable {
        IGameManager.Round memory round = gameManager.getRound(roundId);

        // ── Checks ───────────────────────────────────────────────────────────
        if (round.state != IGameManager.RoundState.OPEN) revert RoundNotOpen();
        if (block.timestamp >= round.bettingWindowEnd) revert BettingWindowExpired();
        if (msg.value < round.minBet) revert BetBelowMinimum(msg.value, round.minBet);
        if (msg.value > round.maxBet) revert BetAboveMaximum(msg.value, round.maxBet);
        if (colour >= round.numColours) revert InvalidColour(colour, round.numColours);
        if (msg.sender == round.house) revert HouseCannotBet();

        // ── Effects ──────────────────────────────────────────────────────────
        uint256 multiplier = _calculateMultiplier(round);

        uint256 betIndex = bets[roundId].length;
        bets[roundId].push(Bet({
            player: msg.sender,
            chosenColour: colour,
            amount: msg.value,
            timestamp: block.timestamp,
            multiplier: multiplier,
            claimed: false
        }));

        playerBetIndices[roundId][msg.sender].push(betIndex);
        totalPot[roundId] += msg.value;

        // ETH is now held in this contract via msg.value — no interaction needed.
        emit BetPlaced(roundId, msg.sender, colour, msg.value, multiplier);
    }

    // ── External: Claim Winnings ─────────────────────────────────────────────

    /// @notice Winning players call this to withdraw their payout after resolution.
    /// @param roundId The ID of the resolved round.
    function claimWinnings(uint256 roundId) external nonReentrant {
        IGameManager.Round memory round = gameManager.getRound(roundId);

        // ── Checks ───────────────────────────────────────────────────────────
        if (round.state != IGameManager.RoundState.RESOLVED) revert RoundNotResolved();

        uint256[] storage indices = playerBetIndices[roundId][msg.sender];
        if (indices.length == 0) revert NoBetsToProcess();

        // Pre-compute distributable pot and total raw payout for scaling
        uint256 feePercent = config.houseFeePercentage();
        uint256 houseFee = (totalPot[roundId] * feePercent) / 100;
        uint256 distributablePot = totalPot[roundId] - houseFee;

        // Calculate the caller's raw payout (pre-scaling)
        uint256 rawPayout = _calcRawPayout(roundId, round.winningColour, indices);
        if (rawPayout == 0) revert NoBetsToProcess();

        // Calculate total raw payouts across ALL players to check for over-distribution
        uint256 totalRawPayout = _calcTotalRawPayout(roundId, round.winningColour);

        // Scale down proportionally if the pot would be exceeded
        uint256 payout;
        if (totalRawPayout > distributablePot) {
            payout = (rawPayout * distributablePot) / totalRawPayout;
        } else {
            payout = rawPayout;
        }

        // ── Effects ──────────────────────────────────────────────────────────
        // Mark bets as claimed BEFORE transferring (checks-effects-interactions)
        for (uint256 i = 0; i < indices.length; i++) {
            Bet storage bet = bets[roundId][indices[i]];
            if (!bet.claimed && bet.chosenColour == round.winningColour) {
                bet.claimed = true;
            }
        }

        // ── Interactions ─────────────────────────────────────────────────────
        (bool ok, ) = msg.sender.call{value: payout}("");
        if (!ok) revert TransferFailed();

        emit WinningsClaimed(roundId, msg.sender, payout);
    }

    // ── External: Claim Refund ───────────────────────────────────────────────

    /// @notice Players call this to get their wager back after a cancellation.
    /// @param roundId The ID of the cancelled round.
    function claimRefund(uint256 roundId) external nonReentrant {
        IGameManager.Round memory round = gameManager.getRound(roundId);

        // ── Checks ───────────────────────────────────────────────────────────
        if (round.state != IGameManager.RoundState.CANCELLED) revert RoundNotCancelled();

        uint256[] storage indices = playerBetIndices[roundId][msg.sender];
        if (indices.length == 0) revert NoBetsToProcess();

        // ── Effects ──────────────────────────────────────────────────────────
        uint256 refund = 0;
        for (uint256 i = 0; i < indices.length; i++) {
            Bet storage bet = bets[roundId][indices[i]];
            if (!bet.claimed) {
                refund += bet.amount;
                bet.claimed = true;
            }
        }

        if (refund == 0) revert NoBetsToProcess();

        // ── Interactions ─────────────────────────────────────────────────────
        (bool ok, ) = msg.sender.call{value: refund}("");
        if (!ok) revert TransferFailed();

        emit RefundClaimed(roundId, msg.sender, refund);
    }

    // ── External: Withdraw House Fee ─────────────────────────────────────────

    /// @notice House calls this once per round to collect the platform fee.
    /// @param roundId The ID of the resolved round.
    function withdrawHouseFee(uint256 roundId) external nonReentrant {
        IGameManager.Round memory round = gameManager.getRound(roundId);

        // ── Checks ───────────────────────────────────────────────────────────
        if (round.state != IGameManager.RoundState.RESOLVED) revert RoundNotResolved();
        if (msg.sender != round.house) revert NotRoundHouse();
        if (houseFeeWithdrawn[roundId]) revert FeeAlreadyWithdrawn();

        // ── Effects ──────────────────────────────────────────────────────────
        uint256 feePercent = config.houseFeePercentage();
        uint256 fee = (totalPot[roundId] * feePercent) / 100;

        houseFeeWithdrawn[roundId] = true;

        // ── Interactions ─────────────────────────────────────────────────────
        (bool ok, ) = msg.sender.call{value: fee}("");
        if (!ok) revert TransferFailed();

        emit HouseFeeWithdrawn(roundId, msg.sender, fee);
    }

    // ── View: Get Bets ───────────────────────────────────────────────────────

    /// @notice Returns all bets placed in a round (public read).
    function getBets(uint256 roundId) external view returns (Bet[] memory) {
        return bets[roundId];
    }

    /// @notice Returns the indices of a specific player's bets in a round.
    function getPlayerBetIndices(uint256 roundId, address player)
        external
        view
        returns (uint256[] memory)
    {
        return playerBetIndices[roundId][player];
    }

    // ── Internal: Multiplier Calculation ────────────────────────────────────

    /// @dev Linear multiplier: maxMultiplier at window start → minMultiplier at window end.
    ///      Both bounds are read from Config (scaled by 1000).
    ///      Falls back to minMultiplier if called at or after window end.
    function _calculateMultiplier(IGameManager.Round memory round)
        internal
        view
        returns (uint256)
    {
        // Read bounds from Config — TODO: expose getters on IConfig and use them.
        // Hard-coded defaults matching spec (§13) until Config getters are wired.
        uint256 maxMul = 3000; // 3.0×
        uint256 minMul = 1000; // 1.0×

        uint256 windowDuration = round.bettingWindowEnd - round.bettingWindowStart;
        if (windowDuration == 0) return minMul;

        uint256 elapsed = block.timestamp - round.bettingWindowStart;
        if (elapsed >= windowDuration) return minMul;

        // multiplier = maxMul - (elapsed / windowDuration) * (maxMul - minMul)
        // Rearranged to avoid division truncation:
        // multiplier = maxMul - ((elapsed * (maxMul - minMul)) / windowDuration)
        uint256 reduction = (elapsed * (maxMul - minMul)) / windowDuration;
        return maxMul - reduction;
    }

    // ── Internal: Payout Helpers ─────────────────────────────────────────────

    /// @dev Raw (unscaled) payout for the calling player's winning bets.
    function _calcRawPayout(
        uint256 roundId,
        uint8 winningColour,
        uint256[] storage indices
    ) internal view returns (uint256 raw) {
        for (uint256 i = 0; i < indices.length; i++) {
            Bet storage bet = bets[roundId][indices[i]];
            if (!bet.claimed && bet.chosenColour == winningColour) {
                raw += (bet.amount * bet.multiplier) / 1000;
            }
        }
    }

    /// @dev Total raw payout across ALL bets on the winning colour (for scaling check).
    function _calcTotalRawPayout(uint256 roundId, uint8 winningColour)
        internal
        view
        returns (uint256 total)
    {
        Bet[] storage allBets = bets[roundId];
        for (uint256 i = 0; i < allBets.length; i++) {
            Bet storage bet = allBets[i];
            if (!bet.claimed && bet.chosenColour == winningColour) {
                total += (bet.amount * bet.multiplier) / 1000;
            }
        }
    }
}

